To fix the flicker, you need to modify the `applyServerUpdate` method in `src/store/optimisticStore.ts` to include a version check. This ensures that a server update is only applied if its version is greater than or equal to the currently stored version, preventing older WebSocket events from overwriting newer optimistic state.

```typescript
// src/store/optimisticStore.ts

  applyServerUpdate(postId: string, count: number, serverVersion: number): PostLikeState {
    const current = this.get(postId);
    // Only apply server update if it's not older than our current state
    // This prevents stale WebSocket events from overwriting newer optimistic or confirmed states.
    if (serverVersion < current.version) {
      console.warn(`[OptimisticStore] Ignoring stale server update for postId ${postId}. Current version: ${current.version}, Server version: ${serverVersion}`);
      return current; // Return current state, do not apply stale update
    }

    const next: PostLikeState = {
      postId,
      count,
      version: serverVersion,
      optimistic: false,
    };
    this.state.set(postId, next);
    return next;
  }
